#!/usr/bin/env python# -*- coding:utf-8 -*-# @Time : 2025/8/25# @Author : cyq# @File : association# @Software: PyCharm# @Desc:from sqlalchemy import Column, Integer, ForeignKey, Index, Boolean, Stringfrom app.model.basic import baseclass RequirementCaseAssociation(base):    __tablename__ = "requirement_case_association"    requirement_id = Column(Integer, ForeignKey('requirement.id', ondelete="CASCADE"), primary_key=True)    case_id = Column(Integer, ForeignKey('test_case.id', ondelete="CASCADE"), primary_key=True)    is_review = Column(Boolean, default=False, comment="是否审核")    case_type = Column(Integer, default=1, comment="用例步骤类型 1'普通' | 2'冒烟' | 3 回归")    case_level = Column(String(5), nullable=False, default="P2", comment="用例步骤等级 P1 P2 P0")    case_status = Column(Integer, default=0, comment="用例步骤状态  0 | 1 | 2; // 0:未开始 1:通过 2:失败")    order = Column(Integer)    __table_args__ = (        Index('idx_req_case_order', 'requirement_id', 'order'),        Index('idx_case_id', 'case_id'),    )